import { defineConfig } from '@lynx-js/rspeedy';
import { pluginVueLynx } from 'vue-lynx/plugin';

// Content workload (first-screen FCP scaling), matrix-driven. The unified
// runner (harness/unified.mjs) sets env per cell so one source builds every
// architecture:
//   BENCH_VAPOR=0|1  renderer mode
//   BENCH_IFR=0|1    enableIFR
//   BENCH_ET=0|1     enableElementTemplates (explicit; never rely on default)
// src/App.vue + src/index.ts are generated by core/workloads/content.mjs.
export default defineConfig({
  environments: {
    web: {},
    lynx: {},
  },
  source: {
    entry: {
      main: './src/index.ts',
    },
  },
  plugins: [
    pluginVueLynx({
      optionsApi: false,
      vapor: process.env.BENCH_VAPOR === '1',
      enableIFR: process.env.BENCH_IFR === '1',
      enableElementTemplates: process.env.BENCH_ET === '1',
    }),
  ],
});
